def rework_policy(self, flow, state, context, tools):
    if not flow.slots['source'].check_if_filled():
        self.ambiguity.declare('specific', metadata={'missing_slot': flow.entity_slot})
        return DisplayFrame(flow.name())

    post_id, sec_id = self._resolve_source_ids(flow, state, tools)

    text, tool_log = self.llm_execute(flow, state, context, tools)
    parsed = self.engineer.apply_guardrails(text) or {}

    if parsed.get('fallback'):
        next_flow = parsed['fallback']
        self.flow_stack.fallback(next_flow)
        state.keep_going = True
        return DisplayFrame(flow.name(),
            thoughts=parsed.get('reason', ''),
            metadata={'fallback': next_flow})

    if parsed.get('needs_clarification'):
        self.ambiguity.declare('confirmation',
            observation=parsed['needs_clarification'])
        return DisplayFrame(flow.name())

    saved, _ = self.engineer.tool_succeeded(tool_log, 'revise_content')
    if not saved:
        return self.error_frame(flow, 'failed_to_save',
            thoughts='revise_content did not land.',
            code=text,
            failed_tool='revise_content')

    flow.status = 'Completed'
    frame = DisplayFrame(flow.name(),
        thoughts=parsed.get('after_summary', ''),
        metadata={'post_id': post_id, 'sec_id': sec_id})
    frame.add_block({'type': 'diff', 'data': parsed})
    return frame

class ReworkFlow(ReviseParentFlow):
  def __init__(self):
    super().__init__()
    self.flow_type = 'rework'
    self.dax = '{006}'
    self.goal = 'major revision of draft content; restructures arguments, replaces weak sections, addresses reviewer comments. Scope can go across the whole post, or an entire section. For smaller changes, use polish'
    self.slots = {
      'source': SourceSlot(1, 'sec'),
      'remove': RemovalSlot(priority='optional'),
      'changes': FreeTextSlot(priority='elective'),
      'suggestions': ChecklistSlot(priority='elective'),
    }
    self.tools = ['read_metadata', 'read_section', 'revise_content', 'insert_section', 'remove_content']
